    pub fn ls(&self) -> Result<(), isize> {
		let inode = self.file.get_dirtree_node();
		let inode = match inode {
			Some(inode) => inode,
			None => return Err(ENOENT),
		};
		if !inode.get_file().is_dir() {
            return Err(ENOTDIR);
        }
        let vec = match inode.get_file().open_subfile() {
            Ok(vec) => vec,
            Err(errno) => return Err(errno),
        };
        for(name, file) in vec {
			//根据颜色输出文件夹和文件并在输出最后一个文件或文件夹时输出换行符
			if file.is_dir() {
				print!("\x1b[34m{}\x1b[0m ", name);
			} else {
				print!("\x1b[32m{}\x1b[0m ", name);
			}
		}
		print!("\n");

		Ok(())
	}
